#include <stdio.h>

int linear_search(int arr[], int size, int target) {
  for (int i = 0; i < size; i++) {
    if (arr[i] == target) {
      return i; // Elementin indeksi qaytarılır
    }
  }
  return -1; // Element tapılmadı
}

int main() {
  int arr[] = {64, 34, 25, 12, 22};
  int size = 5;
  int target = 25;

  int result = linear_search(arr, size, target);
  if (result != -1) {
    printf("%d elementi %d indeksində tapıldı\n", target, result);
  } else {
    printf("%d elementi tapılmadı\n", target);
  }
  return 0;
}
// Output:
// 25 elementi 2 indeksində tapıldı

#include <stdio.h>

int binary_search(int arr[], int low, int high, int target) {
  while (low <= high) {
    int mid = low + (high - low) / 2;
    if (arr[mid] == target) {
      return mid; // Elementin indeksi
    }
    if (arr[mid] < target) {
      low = mid + 1;
    } else {
      high = mid - 1;
    }
  }
  return -1; // Element tapılmadı
}

int main() {
  int arr[] = {12, 22, 25, 34, 64}; // Sıralanmış massiv
  int size = 5;
  int target = 25;

  int result = binary_search(arr, 0, size - 1, target);
  if (result != -1) {
    printf("%d elementi %d indeksində tapıldı\n", target, result);
  } else {
    printf("%d elementi tapılmadı\n", target);
  }
  return 0;
}
// Output:
// 25 elementi 2 indeksində tapıldı

